patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -1,13 +1,13 @@
 module priority_encoder_16bit(
   input [15:0] req,
   input enable,
   output reg [3:0] priority
 );

-  always @(req) begin
+  always @(*) begin
     if (req[15]) priority = 4'd15;
     else if (req[14]) priority = 4'd14;
     else if (req[13]) priority = 4'd13;
     else if (req[12]) priority = 4'd12;
     else priority = 4'd0;
   end

 endmodule

before_code:
module priority_encoder_16bit(
  input [15:0] req,
  input enable,
  output reg [3:0] priority
);

  always @(req) begin
    if (req[15]) priority = 4'd15;
    else if (req[14]) priority = 4'd14;
    else if (req[13]) priority = 4'd13;
    else if (req[12]) priority = 4'd12;
    else priority = 4'd0;
  end

endmodule

after_code:
module priority_encoder_16bit(
  input [15:0] req,
  input enable,
  output reg [3:0] priority
);

  always @(*) begin
    if (req[15]) priority = 4'd15;
    else if (req[14]) priority = 4'd14;
    else if (req[13]) priority = 4'd13;
    else if (req[12]) priority = 4'd12;
    else priority = 4'd0;
  end

endmodule
